def reg_defines():
	'''
	@brief 注册自定义变量到全局变量
	'''
	for k, v in gg.items():
		if not isinstance(v, dict):
			continue

		if 'value' not in v.keys():
			continue

		globals()[k] = v['value']

reg_defines()

